import{c as d,Q as a,j as r,m as e}from"./chunks/framework.CdPW1VM2.js";const _=JSON.parse('{"title":"硬件信息查询","description":"通过 WMI 实时读取 CPU、主板、内存、显卡、硬盘等全面硬件信息，后台线程查询不阻塞 UI。","frontmatter":{"title":"硬件信息查询","description":"通过 WMI 实时读取 CPU、主板、内存、显卡、硬盘等全面硬件信息，后台线程查询不阻塞 UI。"},"headers":[],"relativePath":"guide/hardware.md","filePath":"guide/hardware.md","lastUpdated":null}'),i={name:"guide/hardware.md"};function o(s,t,l,n,c,h){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="硬件信息查询" tabindex="-1">硬件信息查询 <a class="header-anchor" href="#硬件信息查询" aria-label="Permalink to &quot;硬件信息查询&quot;">​</a></h1><p>通过 Windows Management Instrumentation (WMI) 实时读取系统硬件数据，无需安装任何驱动或第三方组件，信息准确可靠。</p><h2 id="支持查询的硬件信息" tabindex="-1">支持查询的硬件信息 <a class="header-anchor" href="#支持查询的硬件信息" aria-label="Permalink to &quot;支持查询的硬件信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>查询内容</th><th>WMI 类</th></tr></thead><tbody><tr><td><i class="fa-solid fa-microchip" style="color:#0078d4;"></i> 处理器</td><td>型号、核心数、线程数、主频、缓存</td><td>Win32_Processor</td></tr><tr><td><i class="fa-solid fa-memory" style="color:#8b5cf6;"></i> 内存</td><td>总容量、可用容量、频率、插槽信息</td><td>Win32_PhysicalMemory</td></tr><tr><td><i class="fa-solid fa-display" style="color:#10b981;"></i> 显卡</td><td>型号、显存、驱动版本</td><td>Win32_VideoController</td></tr><tr><td><i class="fa-solid fa-hard-drive" style="color:#f59e0b;"></i> 硬盘</td><td>型号、容量、接口类型、分区信息</td><td>Win32_DiskDrive</td></tr><tr><td><i class="fa-solid fa-desktop" style="color:#06b6d4;"></i> 显示器</td><td>分辨率、刷新率、制造商</td><td>Win32_DesktopMonitor</td></tr><tr><td><i class="fa-solid fa-network-wired" style="color:#ec4899;"></i> 网卡</td><td>型号、MAC 地址、IP 地址</td><td>Win32_NetworkAdapter</td></tr><tr><td><i class="fa-solid fa-volume-high" style="color:#6366f1;"></i> 声卡</td><td>型号、制造商</td><td>Win32_SoundDevice</td></tr><tr><td><i class="fa-solid fa-server" style="color:#ef4444;"></i> 主板</td><td>制造商、型号、BIOS 版本</td><td>Win32_BaseBoard</td></tr></tbody></table><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li><strong>实时读取</strong> — 每次打开页面都获取最新数据，不缓存过期信息</li><li><strong>后台查询</strong> — WMI 查询在后台线程执行，不阻塞 UI</li><li><strong>分类展示</strong> — 按硬件类别分组，信息一目了然</li><li><strong>零依赖</strong> — 纯 WMI 查询，无需安装额外驱动或工具</li></ul>',6)])])}const m=d(i,[["render",o]]);export{_ as __pageData,m as default};
